#import "JUNDefaultPushNotificationUIDelegate.h"
#import "JUNDefaultPushNotificationUIConfig.h"

@interface JUNDefaultPushNotificationUIDelegate ()

@property(nonatomic, strong, readonly) JUNDefaultPushNotificationUIConfig *config;

@end

@implementation JUNDefaultPushNotificationUIDelegate

static NSString *kUserDefaultIgnoreAuthorizeNotificationAlert = @"webox_ignore_authorize_notification_alert";

+ (instancetype)sharedDelegate {
    static JUNDefaultPushNotificationUIDelegate *delegate = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        JUNDefaultPushNotificationUIConfig *config = [JUNDefaultPushNotificationUIConfig defaultConfig];
        delegate = [[self alloc] initWithConfig:config];
    });
    return delegate;
}

- (instancetype)initWithConfig:(JUNDefaultPushNotificationUIConfig *)config {
    if (self = [super init]) {
        _config = config;
    }
    return self;
}

- (void)onAuthorizationFailed:(NSError *)error {
    if ([self _isIgnoreAuthAlert]) return;
    [self _presentAlertController:[self _createAuthAlertController]];
}

- (Boolean)_isIgnoreAuthAlert {
    return [[NSUserDefaults standardUserDefaults] boolForKey:kUserDefaultIgnoreAuthorizeNotificationAlert] == true;
}

- (void)_setIgnoreAuthAlert:(Boolean)isIgnore {
    [[NSUserDefaults standardUserDefaults] setBool:isIgnore forKey:kUserDefaultIgnoreAuthorizeNotificationAlert];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

- (void)_presentAlertController:(UIAlertController *)alertC {
    UIViewController *rootVc = [WBAppManager getUIApplicationRootViewController];
    [rootVc presentViewController:alertC animated:true completion:nil];
}

- (UIAlertController *)_createAuthAlertController {
    JUNDefaultPushNotificationUIConfig *config = self.config;

    UIAlertController *alertC = [UIAlertController alertControllerWithTitle:config.alertTitle message:config.alertMessage preferredStyle:config.alertStyle];

    [alertC addAction:[self _createOpenSettingsAction]];
    [alertC addAction:[self _createCancelAction]];
    if (self.config.hasIgnoreOption) {
        [alertC addAction:[self _createIgnoreAction]];
    }
    return alertC;
}

- (UIAlertAction *)_createCancelAction {
    return [UIAlertAction actionWithTitle:self.config.cancel style:UIAlertActionStyleCancel handler:nil];
}

- (UIAlertAction *)_createIgnoreAction {
    return [UIAlertAction actionWithTitle:self.config.ignore style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        [self _setIgnoreAuthAlert:true];
        [self _presentAlertController:[self _createAfterIgnoreAlertController]];
    }];
}

- (UIAlertController *)_createAfterIgnoreAlertController {
    JUNDefaultPushNotificationUIConfig *config = self.config;
    UIAlertController *alertC = [UIAlertController alertControllerWithTitle:config.afterIgnoreTitle message:config.afterIgnoreMessage preferredStyle:UIAlertControllerStyleAlert];
    UIAlertAction *confirm = [UIAlertAction actionWithTitle:config.confirm style:UIAlertActionStyleDefault handler:nil];
    [alertC addAction:confirm];
    return alertC;
}

- (UIAlertAction *)_createOpenSettingsAction {
    return [UIAlertAction actionWithTitle:self.config.openSettings style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        [self _openSettings];
    }];
}

- (NSString *)_getOpenSettingsURLstring {
    if (@available(iOS 15.4, *)) {
        return UIApplicationOpenNotificationSettingsURLString;
    } else {
        return [UIApplicationOpenSettingsURLString stringByAppendingString:[[NSBundle mainBundle] bundleIdentifier]];
