    // to be implemented by subclasses
}

- (void)_requestAuthorization {
    UNAuthorizationOptions opts = UNAuthorizationOptionBadge | UNAuthorizationOptionSound | UNAuthorizationOptionAlert;
    [[UNUserNotificationCenter currentNotificationCenter] requestAuthorizationWithOptions:opts completionHandler:^(BOOL granted, NSError * _Nullable error) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (granted) {
                [self _registerForPushNotification];
                return;
            }else{// 如果不同意，就传输空的 DeviceToken
                [self _handleAuthorizationFailed:error];
            }
        });
    }];
}

- (void)_handleAuthorizationFailed:(NSError *)error {
//    [self sendDeviceTokenToServer:nil withVappBundleId:nil];  // 注释掉：在未同意通知权限时，不再发空DeviceToken给服务器
    [self _observeAuthStatusWhenEnterForeground];
    if (self.uiDelegate != nil && [self.uiDelegate respondsToSelector:@selector(onAuthorizationFailed:)]) {
        [self.uiDelegate onAuthorizationFailed:error];
    }
}


- (void)_observeAuthStatusWhenEnterForeground {
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(_appOnEnterForeground) name:UIApplicationWillEnterForegroundNotification object:nil];
}

- (void)_cancelObserveAuthStatusWhenEnterForeground {
    [[NSNotificationCenter defaultCenter] removeObserver:self name:UIApplicationWillEnterForegroundNotification object:nil];
}

- (void)_appOnEnterForeground {
    [[UNUserNotificationCenter currentNotificationCenter] getNotificationSettingsWithCompletionHandler:^(UNNotificationSettings * _Nonnull settings) {
        if (settings.authorizationStatus != UNAuthorizationStatusAuthorized) return;
        [self _registerForPushNotification];
        [self _cancelObserveAuthStatusWhenEnterForeground];
    }];
}

- (id<JUNPushNotificationUIDelegate>)_getUIDelegate {
    return [JUNDefaultPushNotificationUIDelegate sharedDelegate];
}

@end

